bool is_provably_segwit(const std::shared_ptr<Script> &script_pubkey, std::shared_ptr<Script> redeem_script) {
    auto ret = uniffi::rust_call(
        uniffi_lwk_fn_func_is_provably_segwit,
        nullptr, uniffi::FfiConverterScript::lower(script_pubkey), uniffi::FfiConverterOptionalScript::lower(redeem_script));

    return uniffi::FfiConverterBool::lift(ret);
}
